#!/usr/bin/env bash
# LocateAnything - EndoVis COCO-style AP/mAP evaluation.
#
# Requires data generated by:
#   Embodied/tools/prepare_endovis_locany.py --collapse-class --modes grounding ...
#
# Inputs:
#   annotations/endovis_val_eval.jsonl  - inference prompts
#   annotations/endovis_val_coco.json   - COCO-format GT for AP/mAP
set -euo pipefail

GPUS=${GPUS:-1}
MODEL_PATH=${MODEL_PATH:-"work_dirs/locany_lora_endovis_single/checkpoint-1000"}
ENDOVIS_ROOT=${ENDOVIS_ROOT:-"../data/endovis_locany_single"}
TEST_JSONL_PATH=${TEST_JSONL_PATH:-"${ENDOVIS_ROOT}/annotations/endovis_val_eval.jsonl"}
IMAGE_ROOT_DIR=${IMAGE_ROOT_DIR:-"${ENDOVIS_ROOT}/images"}
COCO_JSON=${COCO_JSON:-"${ENDOVIS_ROOT}/annotations/endovis_val_coco.json"}
OUTPUT_DIR=${OUTPUT_DIR:-"work_dirs/locany_lora_endovis_single/eval_val_map"}
GENERATION_MODE=${GENERATION_MODE:-"hybrid"}

print_help() {
    echo "Usage: $0 [OPTIONS]"
    echo ""
    echo "  --model_path PATH       Checkpoint/model path"
    echo "  --endovis_root DIR      Prepared EndoVis root (default: ../data/endovis_locany_single)"
    echo "  --test_jsonl PATH       Override endovis_val_eval.jsonl"
    echo "  --image_root DIR        Override image root"
    echo "  --coco_json PATH        Override endovis_val_coco.json"
    echo "  --output_dir DIR        Output directory"
    echo "  --generation_mode MODE  fast | slow | hybrid"
}

while [[ $# -gt 0 ]]; do
    case "$1" in
        --model_path)      MODEL_PATH="$2"; shift 2;;
        --endovis_root)    ENDOVIS_ROOT="$2"; TEST_JSONL_PATH="$2/annotations/endovis_val_eval.jsonl"; IMAGE_ROOT_DIR="$2/images"; COCO_JSON="$2/annotations/endovis_val_coco.json"; shift 2;;
        --test_jsonl)      TEST_JSONL_PATH="$2"; shift 2;;
        --image_root)      IMAGE_ROOT_DIR="$2"; shift 2;;
        --coco_json)       COCO_JSON="$2"; shift 2;;
        --output_dir)      OUTPUT_DIR="$2"; shift 2;;
        --generation_mode) GENERATION_MODE="$2"; shift 2;;
        -h|--help)         print_help; exit 0;;
        *)                 echo "Unknown option: $1"; print_help; exit 1;;
    esac
done

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
export GPUS
export LOCANY_VISION_ATTN="${LOCANY_VISION_ATTN:-sdpa}"

bash "$SCRIPT_DIR/eval_coco.sh" \
    --model_path "$MODEL_PATH" \
    --test_jsonl "$TEST_JSONL_PATH" \
    --image_root "$IMAGE_ROOT_DIR" \
    --coco_json "$COCO_JSON" \
    --output_dir "$OUTPUT_DIR" \
    --generation_mode "$GENERATION_MODE"
